record_types.code:
type Negotiation (Auto : Boolean := True) is record
   case Auto is
      when True =>
         Restart : Boolean;
      when False =>
         Speed  : Negotiation_Speed;
         Duplex : Duplex_Mode;
   end case;
end record;

type PHY_Status is record
   l00_BASE_T4               : Boolean;
   l00_BASE_X_Full_Duplex    : Boolean;
   l00_BASE_X_Half_Duplex    : Boolean;
   l0_BASE_T_Full_Duplex     : Boolean;
   l0_BASE_T_Half_Duplex     : Boolean;
   l00_BASE_T2_Full_Duplex   : Boolean;
   l00_BASE_T2_Half_Duplex   : Boolean;
   Extended_Status           : Boolean;
   MF_Preamble_Suppression   : Boolean;
   Auto_Negotiation_Complete : Boolean;
   Remote_Fault              : Boolean;
   Auto_Negotiation_Ability  : Boolean;
   Link_Up                   : Boolean;
   Jabber_Detect             : Boolean;
   Extended_Capability       : Boolean;
end record;

